// 三载体一致:纯 JS、无 DOM/uplink/shadow 足迹
import { PaymentDueTime, pmt, irr, npv } from 'https://cdn.jsdelivr.net/npm/financial@0/+esm';
let result;
if (data.kind === 'pmt') result = pmt(data.rate, data.periods, data.present_value, data.future_value ?? 0, data.due === 'begin' ? PaymentDueTime.Begin : PaymentDueTime.End);
else if (data.kind === 'irr') result = irr(data.cashflows, data.guess ?? 0.1, data.tolerance ?? 1e-6, data.max_iterations ?? 100);
else if (data.kind === 'npv') result = npv(data.rate, data.cashflows);
else throw new Error('Unsupported financial function');
